(1, '¿ME PREGUNTO EL NOMBRE?', 'libre', 1, 10.00, 2, 3, 1, NULL, '2024-06-04 22:59:37', '2024-06-04 22:59:37'),
(2, 'QUE DIA ES HOY?', 'libre', 1, 25.00, 2, 3, 2, NULL, '2024-06-04 23:01:07', '2024-06-04 23:01:07'),
(3, '¿COMO TE LLAMAS?', 'libre', 1, 50.00, 2, 3, 2, NULL, '2024-06-04 23:01:38', '2024-06-04 23:01:38'),
(4, '¿EL TéCNICO INSTALO LOS PROTECTORES DE TIMóN, ASIENTO, PISO Y PALANCA?', 'libre', 1, 2.00, 1, 3, 3, NULL, '2024-06-08 17:43:18', '2024-06-08 17:43:18'),
(5, '¿EL TECNICO REVISO LOS 4 FRENOS?', 'libre', 1, 3.00, 1, 3, 3, NULL, '2024-06-08 18:20:08', '2024-06-08 18:20:08'),
(6, '¿EL TéCNICO REVISO EL ESTADO DE LAS PUERTAS?', 'libre', 1, 5.00, 1, 3, 3, NULL, '2024-06-08 18:24:18', '2024-06-08 18:24:18'),
(7, '¿EL TéCNICO SE DIO CUENTA DEL BOMBILLO DAñADO?', 'libre', 1, 10.00, 1, 3, 3, NULL, '2024-06-08 18:24:58', '2024-06-08 18:24:58'),
(8, '¿EL TéCNICO SE DIO CUENTA QUE EL CAMIóN NO TENIA UREA?', 'libre', 1, 10.00, 1, 3, 3, NULL, '2024-06-08 18:25:16', '2024-06-08 18:25:16'),
(9, '¿EL TéCNICO SE PRESENTO Y LE PREGUNTO SUS DATOS?', 'libre', 1, 2.00, 1, 3, 4, NULL, '2024-06-08 18:26:13', '2024-06-08 18:26:13'),
(10, '¿EL TéCNICO RESOLVIó SUS DUDAS ADECUADAMENTE?', 'libre', 1, 3.00, 1, 3, 4, NULL, '2024-06-08 18:26:40', '2024-06-08 18:26:40'),
(11, '¿EL TéCNICO CONOCE LOS DETALLES MECáNICOS DE EURO VI?', 'libre', 1, 3.00, 1, 3, 5, NULL, '2024-06-08 18:27:15', '2024-06-08 18:27:15'),
(12, '¿EL TéCNICO USA A SU FAVOR LAS VIRTUDES DE LA NUEVA TECNOLOGIA?', 'libre', 1, 2.00, 1, 3, 5, NULL, '2024-06-08 18:27:51', '2024-06-08 18:27:51'),
(13, '¿EL CLIENTE SE PRESENTO Y PIDIó SU VIN?', 'libre', 1, 5.00, 1, 3, 6, NULL, '2024-06-08 20:27:10', '2024-06-08 20:27:10'),
(14, '¿EL ASESOR LE PIDIó EL CAMIóN POR EL CUAL NECESITA LOS REPUESTOS?', 'libre', 1, 0.50, 1, 3, 6, NULL, '2024-06-08 20:27:48', '2024-06-08 20:27:48'),
(15, '¿Prueba De La Letra, Mayusculas En Todas Las Letras?', 'libre', 1, 1.50, 1, 3, 6, NULL, '2024-06-09 02:10:13', '2024-06-09 02:10:13'),
(16, '¿Prueba pregunta bien hecha con corazón y minusculas?', 'libre', 1, 3.00, 1, 3, 6, NULL, '2024-06-09 02:11:33', '2024-06-09 02:11:33'),
(17, '¿Texto final?', 'libre', 1, 40.00, 1, 3, 7, NULL, '2024-06-09 02:15:19', '2024-06-09 02:15:19'),
(18, '¿El técnico instalo los protectores de timón, asiento, piso y palanca? ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:26:44', '2024-06-09 03:26:44'),
(19, '¿El técnico reviso el funcionamiento de las luces exteriores y bocina? Funcionamiento y estado de altas - medias - bajas -direccionales - exploradoras - reversa - freno - posición - placa (Estado de las mismas, si se encuentran rotas o con agua) ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:28:20', '2024-06-09 03:28:20'),
(20, '¿El técnico detecto la falla del bombillo fundido?', 'libre', 1, 2.00, 1, 3, 8, NULL, '2024-06-09 03:28:40', '2024-06-09 03:28:40'),
(21, '¿El técnico reviso los niveles delanteros y de parabrisas? Liquido de frenos - Embrague - Limpia Parabrisas ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:29:28', '2024-06-09 03:29:28'),
(22, '¿El técnico midió el nivel de humedad del liquido de frenos, detectando que el nivel correcto es 2%?', 'libre', 1, 2.00, 1, 3, 8, NULL, '2024-06-09 03:30:07', '2024-06-09 03:30:07'),
(23, '¿El técnico reviso los niveles de motor y fugas? Nivel de aceite de motor - Nivel de embrague - Fugas de motor - Fugas de culata - Fugas en el filtro de aceite - Fugas en el filtro de combustible (Debe mostrar la marca X y el nivel de aceite) ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:31:34', '2024-06-09 03:31:34'),
(24, '¿El técnico reviso el radiador? Fugas - Nivel del refrigerante - Tapa - Golpes (De manera visual)', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:32:14', '2024-06-09 03:32:14'),
(25, '¿El técnico reviso las correas? Revisar tensión y condición de la correa del alternador - Compresor A/A - Equipo de refrigeración (No es necesario realizar tensión)', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:33:13', '2024-06-09 03:33:13'),
(26, '¿El técnico reviso la dirección? Nivel de la dirección asistida - Fugas en la caja de dirección - Estado de los terminales - Guardapolvo ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:34:02', '2024-06-09 03:34:02'),
(27, '¿El técnico reviso la 4 suspensiones de rueda?  Amortiguadores - Ballestas - Cauchos - Bujes - Fractura de hojas  (Revisión visual)', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:34:23', '2024-06-09 03:34:23'),
(28, '¿El técnico reviso los frenos de las 4 ruedas ? Fugas de cilindro de frenos - Cámaras de frenos  (Inspección visual) ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:35:20', '2024-06-09 03:35:20'),
(29, '¿El técnico reviso el conjunto de las 4 ruedas?  Estado de banda de rodamiento - Presión - Ajuste de pernos - Posición de las válvulas de inflado ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:35:40', '2024-06-09 03:35:40'),
(30, '¿El técnico detecto el perno que se encontraba suelto ? ', 'libre', 1, 2.00, 1, 3, 8, NULL, '2024-06-09 03:35:57', '2024-06-09 03:35:57'),
(31, '¿El técnico reviso la admisión del camión? Estado del filtro de aire - Manguera - Admisión de aire turbo a intercooler y a motor  (Inspección visual) ', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:36:11', '2024-06-09 03:36:11'),
(32, '¿El técnico reviso los niveles y calidad de los fluidos? Refrigerante (Refractómetro - Concentración 50% Agua / 50% Refrigerante) - Nivel dirección asistida y frenos  (Debe realizar una medición con el instrumento)', 'libre', 1, 0.50, 1, 3, 8, NULL, '2024-06-09 03:36:33', '2024-06-09 03:36:33'),
(33, '¿El técnico reviso los niveles y calidad de la urea?  Nivel de Urea y mezcla 32.5% Debe realizar una medición con el instrumento', 'libre', 1, 1.00, 1, 3, 8, NULL, '2024-06-09 03:37:00', '2024-06-09 03:37:00'),
