(1636, 1534, 31, 'Equilibra una muy buena maniobrabilidad en entornos urbanos con una excelente comodidad en viajes largos.', '2025-10-29 13:43:10', '2025-10-29 13:43:10', 31, 12.50),
(1637, 1534, 31, 'Es la que proporciona mayor espacio interior a los ocupantes, ya que las sillas están más separadas entre si.', '2025-10-29 13:43:10', '2025-10-29 13:43:10', 31, 0.00),
(1638, 1534, 31, 'Esto permite que tenga una mayor altura a piso, lo que favorece su desempeño en condiciones off road.', '2025-10-29 13:43:10', '2025-10-29 13:43:10', 31, 0.00),
(1639, 1534, 31, 'La distancia entre ejes hace que tenga un mejor ángulo de ataque y salida, lo que facilita el paso por rampas de acceso sin golpear el vehículo por debajo.', '2025-10-29 13:43:10', '2025-10-29 13:43:10', 31, 0.00),
(1640, 1535, 31, 'Una persona intenta ingresar al vehículo mientras la puerta eléctrica se está abriendo.', '2025-10-29 13:43:57', '2025-10-29 13:43:57', 31, 12.50),
(1641, 1535, 31, 'El sistema Blis detecta que se está aproximando un vehículo.', '2025-10-29 13:43:57', '2025-10-29 13:43:57', 31, 0.00),
