(2165, 1633, 31, 'Su barra de techo con capacidad de 50 kilos.', '2025-10-29 16:10:13', '2025-10-29 16:10:13', 31, 0.00),
(2197, 1641, 31, 'Las luces delanteras de la Ford Territory.', '2025-10-29 15:45:00', '2025-10-29 15:45:00', 31, 3.00),
(2198, 1641, 31, 'El largo total de la camioneta.', '2025-10-29 15:45:00', '2025-10-29 15:45:00', 31, 0.00),
(2199, 1641, 31, 'La autonomía que le permite recorrer tres veces más distancia que su principal competidor.', '2025-10-29 15:45:00', '2025-10-29 15:45:00', 31, 0.00),
(2200, 1641, 31, 'Las protecciones inferiores, que van de bómper a bómper y cubren todos los elementos mecánicos y eléctricos de la camioneta.', '2025-10-29 15:45:00', '2025-10-29 15:45:00', 31, 0.00),
(2201, 1642, 31, 'Es menos exigente con la batería, contribuyendo a extender su vida útil.', '2025-10-29 15:46:01', '2025-10-29 15:46:01', 31, 0.00),
(2202, 1642, 31, 'Si una bombilla se funde, puede cambiarse individualmente sin reponer todo el componente.', '2025-10-29 15:46:01', '2025-10-29 15:46:01', 31, 3.00),
(2203, 1642, 31, 'Proporcionan un mayor alcance y contraste que las luces convencionales.', '2025-10-29 15:46:01', '2025-10-29 15:46:01', 31, 0.00),
(2204, 1642, 31, 'Su menor temperatura previene daños en los circuitos y piezas plásticas.', '2025-10-29 15:46:01', '2025-10-29 15:46:01', 31, 0.00),
(2205, 1643, 31, 'Contribuyen a la reducción de peso de la camioneta.', '2025-10-29 15:46:51', '2025-10-29 15:46:51', 31, 0.00),
(2206, 1643, 31, 'Contribuyen a incrementar la altura total de la camioneta.', '2025-10-29 15:46:51', '2025-10-29 15:46:51', 31, 0.00),
(2207, 1643, 31, 'Ayuda a mejorar la estabilidad, un manejo más firme en curvas y mayor aprovechamiento de la energía en alta velocidad.', '2025-10-29 15:46:51', '2025-10-29 15:46:51', 31, 3.00),
(2208, 1643, 31, 'Incrementan la capacidad portante de las llantas, y con ello la capacidad de carga.', '2025-10-29 15:46:51', '2025-10-29 15:46:51', 31, 0.00),
(2209, 1644, 31, 'Es la que proporciona mayor espacio interior a los ocupantes, ya que las sillas están más separadas entre si.', '2025-10-29 15:48:24', '2025-10-29 15:48:24', 31, 0.00),
(2210, 1644, 31, 'Esto permite que tenga una mayor altura a piso, lo que favorece su desempeño en condiciones off road.', '2025-10-29 15:48:24', '2025-10-29 15:48:24', 31, 0.00),
(2211, 1644, 31, 'Equilibra una muy buena maniobrabilidad en entornos urbanos con una excelente comodidad en viajes largos.', '2025-10-29 15:48:24', '2025-10-29 15:48:24', 31, 3.00),
(2212, 1644, 31, 'La distancia entre ejes hace que tenga un mejor ángulo de ataque y salida, lo que facilita el paso por rampas de acceso sin golpear el vehículo por debajo.', '2025-10-29 15:48:24', '2025-10-29 15:48:24', 31, 0.00),
(2213, 1645, 31, 'Una persona intenta ingresar al vehículo mientras la puerta eléctrica se está abriendo.', '2025-10-29 15:49:16', '2025-10-29 15:49:16', 31, 3.00),
(2214, 1645, 31, 'El sistema Blis detecta que se está aproximando un vehículo.', '2025-10-29 15:49:16', '2025-10-29 15:49:16', 31, 0.00),
(2215, 1645, 31, 'Se presiona el botón de encendido para apagar el sistema de propulsión del vehículo.', '2025-10-29 15:49:16', '2025-10-29 15:49:16', 31, 0.00),
(2216, 1645, 31, 'Cuando el selector de cambios pasa de P a D o R.', '2025-10-29 15:49:16', '2025-10-29 15:49:16', 31, 0.00),
